export type PahlenProductVariant = {
  label: string;
  sku: string;
  price: number;
};

export type PahlenProduct = {
  sku: string;
  name: string;
  price: number | null;
  /** Shopify variant GID — set once product is published in Shopify */
  shopifyVariantId?: string;
  /** Selectable sub-models — price changes per selection */
  variants?: PahlenProductVariant[];
  /** Filter group shown as a tab on the category page */
  group?: string;
};

/**
 * Apply standard 25% retail markup to a Pahlén base price.
 * Always use this when displaying Pahlén prices on the site.
 */
export function pahlenPrice(base: number | null): number | null {
  if (base === null) return null;
  return Math.round(base * 1.25);
}

